from __future__ import annotations

import asyncio
import socket
import threading
from collections.abc import Callable
from selectors import EVENT_READ, EVENT_WRITE, DefaultSelector
from typing import TYPE_CHECKING, Any

if TYPE_CHECKING:
    from _typeshed import FileDescriptorLike

_selector_lock = threading.Lock()
_selector: Selector | None = None


class Selector:
    def __init__(self) -> None:
        """Initialize the selector, internal socketpair for notifications, and thread."""
        self._thread = threading.Thread(target=self.run, name="AnyIO socket selector")
        self._selector = DefaultSelector()
        self._send, self._receive = socket.socketpair()
        self._send.setblocking(False)
        self._receive.setblocking(False)
        # This somewhat reduces the amount of memory wasted queueing up data
        # for wakeups. With these settings, maximum number of 1-byte sends
        # before getting BlockingIOError:
        #   Linux 4.8: 6
        #   macOS (darwin 15.5): 1
        #   Windows 10: 525347
        # Windows you're weird. (And on Windows setting SNDBUF to 0 makes send
        # blocking, even on non-blocking sockets, so don't do that.)
        self._receive.setsockopt(socket.SOL_SOCKET, socket.SO_RCVBUF, 1)
        self._send.setsockopt(socket.SOL_SOCKET, socket.SO_SNDBUF, 1)
        # On Windows this is a TCP socket so this might matter. On other
        # platforms this fails b/c AF_UNIX sockets aren't actually TCP.
        try:
            self._send.setsockopt(socket.IPPROTO_TCP, socket.TCP_NODELAY, 1)
        except OSError:
            pass

        self._selector.register(self._receive, EVENT_READ)
        self._closed = False

    def start(self) -> None:
        """Start the selector thread and register shutdown handler."""
        self._thread.start()
        threading._register_atexit(self._stop)  # type: ignore[attr-defined]

    def _stop(self) -> None:
        """Stop the selector thread and clean up resources."""
        global _selector
        self._closed = True
        self._notify_self()
        try:
            self._send.close()
        except OSError:
            pass
        self._thread.join()
        try:
            self._selector.unregister(self._receive)
        except Exception:
            pass
        try:
            self._receive.close()
        except OSError:
            pass
        try:
            self._selector.close()
        except Exception:
            pass
        _selector = None
        assert not self._selector.get_map(), (
            "selector still has registered file descriptors after shutdown"
        )

    def _notify_self(self) -> None:
        """Wake up the selector thread by writing a byte to the internal socket."""
        try:
            self._send.send(b"\x00")
        except BlockingIOError:
            pass
        except OSError:
            # Ignore errors that might happen during shutdown/close
            pass

    def add_reader(self, fd: FileDescriptorLike, callback: Callable[[], Any]) -> None:
        """Register a file descriptor for read readiness and associate a callback."""
        loop = asyncio.get_running_loop()
        try:
            key = self._selector.get_key(fd)
        except KeyError:
            self._selector.register(fd, EVENT_READ, {EVENT_READ: (loop, callback)})
        else:
            if EVENT_READ in key.data:
                raise ValueError(
                    "this file descriptor is already registered for reading"
                )

            key.data[EVENT_READ] = loop, callback
            self._selector.modify(fd, key.events | EVENT_READ, key.data)

        self._notify_self()

    def add_writer(self, fd: FileDescriptorLike, callback: Callable[[], Any]) -> None:
        """Register a file descriptor for write readiness and associate a callback."""
        loop = asyncio.get_running_loop()
        try:
            key = self._selector.get_key(fd)
        except KeyError:
            self._selector.register(fd, EVENT_WRITE, {EVENT_WRITE: (loop, callback)})
        else:
            if EVENT_WRITE in key.data:
                raise ValueError(
                    "this file descriptor is already registered for writing"
                )

            key.data[EVENT_WRITE] = loop, callback
            self._selector.modify(fd, key.events | EVENT_WRITE, key.data)

        self._notify_self()

    def remove_reader(self, fd: FileDescriptorLike) -> bool:
        """Unregister read readiness for the given file descriptor.

        Returns True if the descriptor was registered and removed, False otherwise.
        """
        try:
            key = self._selector.get_key(fd)
        except KeyError:
            return False

        if new_events := key.events ^ EVENT_READ:
            # If other events remain, remove only the read entry.
            del key.data[EVENT_READ]
            self._selector.modify(fd, new_events, key.data)
        else:
            # No events left; fully unregister.
            self._selector.unregister(fd)

        return True

    def remove_writer(self, fd: FileDescriptorLike) -> bool:
        """Unregister write readiness for the given file descriptor.

        Returns True if the descriptor was registered and removed, False otherwise.
        """
        try:
            key = self._selector.get_key(fd)
        except KeyError:
            return False

        if new_events := key.events ^ EVENT_WRITE:
            del key.data[EVENT_WRITE]
            self._selector.modify(fd, new_events, key.data)
        else:
            self._selector.unregister(fd)

        return True

    def run(self) -> None:
        """Selector thread main loop: wait for events and dispatch callbacks in their loops."""
        recv = self._receive
        selector = self._selector
        while not self._closed:
            try:
                events = selector.select()
            except OSError:
                # If the selector is closed or an invalid FD was encountered, break.
                break

            for key, mask in events:
                # Internal wakeup socket: drain it and continue.
                if key.fileobj is recv:
                    try:
                        # Drain available data.
                        while True:
                            recv.recv(1024)
                    except (BlockingIOError, InterruptedError):
                        pass
                    except OSError:
                        # If closed during shutdown, ignore.
                        pass
                    continue

                data = key.data
                # Dispatch read callback if relevant.
                if mask & EVENT_READ and EVENT_READ in data:
                    loop, callback = data[EVENT_READ]
                    try:
                        loop.call_soon_threadsafe(callback)
                    except RuntimeError:
                        # Loop is closed; ignore.
                        pass

                # Dispatch write callback if relevant.
                if mask & EVENT_WRITE and EVENT_WRITE in data:
                    loop, callback = data[EVENT_WRITE]
                    try:
                        loop.call_soon_threadsafe(callback)
                    except RuntimeError:
                        pass


def get_selector() -> Selector:
    """Get the global selector, creating and starting it if necessary."""
    global _selector
    with _selector_lock:
        if _selector is None:
            _selector = Selector()
            _selector.start()
        return _selector